import { Component, h, Prop, Host, State, Element } from '@stencil/core';
import { twMerge } from '../../utils/utils';
import { DividerAlignment, DividerOrientation, DividerVariant } from './wdpr-divider.model';

@Component({
  tag: 'wdpr-divider',
  shadow: true,
})
export class WdprDivider {
  @Element() el!: HTMLElement;

  @State() slot: HTMLElement | null = null;

  @Prop() orientation: DividerOrientation = 'horizontal';
  @Prop() align: DividerAlignment = 'left';
  @Prop() variant: DividerVariant = 'primary';

  componentWillLoad() {
    this._updateSlot();
  }

  private _updateSlot = () => {
    this.slot = this.el.querySelector('[slot="label"]');
  };

  private get strokeVar(): string {
    return this.variant === 'secondary' ? 'var(--stroke-050)' : 'var(--stroke-012)';
  }

  get separatorClass() {
    const base = 'bg-stroke-default border-0 m-0 shrink-0';

    return this.orientation === 'horizontal' ? twMerge(base, 'flex-1 w-auto') : twMerge(base, 'h-full');
  }

  get separatorStyle() {
    return this.orientation === 'horizontal' ? { height: this.strokeVar } : { width: this.strokeVar };
  }

  render() {
    const isHorizontal = this.orientation === 'horizontal';
    const hasLabel = !!this.slot;

    if (!isHorizontal) {
      return (
        <Host>
          <hr aria-orientation="vertical" class={this.separatorClass} style={this.separatorStyle} />
        </Host>
      );
    }

    const labelMarginClass = this.align === 'center' ? 'mx-075' : this.align === 'right' ? 'ml-075' : 'mr-075';

    return (
      <Host>
        <div class="flex items-center w-full">
          {this.align !== 'left' && <hr class={this.separatorClass} style={this.separatorStyle} />}

          {hasLabel && (
            <span class={twMerge('inline-block', labelMarginClass)}>
              <slot name="label" onSlotchange={this._updateSlot} />
            </span>
          )}

          {this.align !== 'right' && <hr class={this.separatorClass} style={this.separatorStyle} />}
        </div>
      </Host>
    );
  }
}
